solutions.javascript:
// Solution: Check if the 'type' attribute is either '1' or '2'
function validateListTag(htmlTag) {
  if (htmlTag.includes('type="1"') || htmlTag.includes('type="2"')) {
    return htmlTag;
  } else {
    return 'Error: Invalid 'type' attribute.';
  }
}

